import React from 'react';
import { View, Button, Alert } from 'react-native';
import InAppPurchase from 'react-native-iap';
import { PaymentProvider } from 'some-digital-wallet-sdk';

const paymentProviderConfig = {
  apiKey: 'your-api-key',
  environment: 'production',
};

PaymentProvider.initialize(paymentProviderConfig);

class PaymentModule extends React.Component {
  componentDidMount() {
    this.initInAppPurchase();
  }

  initInAppPurchase = async () => {
    try {
      await InAppPurchase.initConnection();
      this.purchaseUpdateSubscription = InAppPurchase.purchaseUpdatedListener(this.onPurchaseUpdate);
      this.purchaseErrorSubscription = InAppPurchase.purchaseErrorListener(this.onPurchaseError);
    } catch (error) {
      console.error('InAppPurchase connection error', error);
    }
  };

  onPurchaseUpdate = purchase => {
    // Handle successful purchase
    console.log('Purchase successful', purchase);
  };

  onPurchaseError = error => {
    // Handle purchase error
    console.error('Purchase error', error);
  };

  handleInAppPurchase = async productId => {
    try {
      await InAppPurchase.requestPurchase(productId);
    } catch (error) {
      console.error('InAppPurchase request error', error);
    }
  };

  handleDigitalWalletTransaction = async transactionDetails => {
    try {
      const response = await PaymentProvider.processTransaction(transactionDetails);
      if (response.success) {
        Alert.alert('Transaction Successful');
      } else {
        Alert.alert('Transaction Failed', response.errorMessage);
      }
    } catch (error) {
      console.error('Digital wallet transaction error', error);
    }
  };

  componentWillUnmount() {
    if (this.purchaseUpdateSubscription) {
      this.purchaseUpdateSubscription.remove();
    }
    if (this.purchaseErrorSubscription) {
      this.purchaseErrorSubscription.remove();
    }
    InAppPurchase.endConnection();
  }

  render() {
    return (
      <View>
        <Button
          title="Purchase Product"
          onPress={() => this.handleInAppPurchase('product_id')}
        />
        <Button
          title="Pay with Digital Wallet"
          onPress={() => this.handleDigitalWalletTransaction({ amount: 100, currency: 'USD' })}
        />
      </View>
    );
  }
}

export default PaymentModule;